import { createEl, SI, number } from './utils.js';

import './Table.css';

const $input = document.querySelector('#file');

$input.addEventListener('change', e => {
  const file = $input.files[0];
  $root.querySelector('header span').textContent = file.name.replace('.csv', '');
  const reader = new FileReader();
  $input.style.display = 'none';
  reader.onload = () => onLoad(reader.result);
  reader.onerror = e => alert(e);
  reader.readAsText(file);
});

const LINK = 0,
  NAME = 1,
  ICON = 2,
  AFFINITY = 3,
  INF_POWER = 4,
  VIEWS = 5,
  USERS = 6,
  AGE = 7,
  GENDER = 8;

const CELL_ORDER = [
  NAME,
  AFFINITY,
  INF_POWER,
  VIEWS,
  USERS,
  AGE,
  GENDER,
];

const NUMBER_CELLS = [
  AFFINITY,
  INF_POWER,
  VIEWS,
  USERS,
];

const STAT_CELLS = [AGE, GENDER];

const $root = document.querySelector('#root');

function onLoad (data) {
  const lines = data.split(/\r\n/).map(line => {
    return line.split(',');
  });

  const head = lines[0];
  const rows = lines.slice(1, 101);

  const $table = renderTable({ head, rows });
  $table.classList.add('Table');

  $root.append($table);
}

function renderTable ({ head, rows }) {
  return createEl('table', { cellSpacing: 10 }, [
    createEl(
      'thead',
      null,
      CELL_ORDER.map(field =>
        createEl('th', null, head[field])
      ),
    ),

    createEl('tbody', null,
      rows.map((row, ri) => {
        if (!row)
          return null;
        return createEl('tr', null,
          CELL_ORDER.map((field, fi) => {
            const cell = row[field];

            if (field === NAME) {
              return createEl('td', null, [
                createEl('div', null, [
                  createEl('img', {
                    src: row[ICON],
                    lazy: 'lazy',
                  }),
                  createEl('span', null, cell),
                  createEl('a', {
                    href: row[LINK],
                    target: '_blank',
                  }, 'Youtube link'),
                ])
              ])
            }

            if (NUMBER_CELLS.includes(field)) {
              return createEl('td', { className: '--number' }, SI(+cell))
            }

            if (STAT_CELLS.includes(field)) {
              const stats = cell.replace(/^"|"$/g, '')
                .split('\n').map(stat => {
                  const [ name, value ] = stat.split(' : ');
                  return { name, value };
                });

              if (!stats?.[0].name?.length)
                return createEl('td');

              if (field === AGE) {
                stats.sort((a, b) => {
                  const aa = a.name.charAt(0);
                  const bb = b.name.charAt(0);
                  return aa < bb ? -1 : aa == bb ? 0 : 1;
                })
              }

              return createEl('td', { className: '--stats' }, [
                createEl('dl', null,
                  stats.reduce((acc, stat) => {
                      acc.push(createEl('dt', null, stat.name));
                      acc.push(createEl('dd', null, stat.value));
                      return acc;
                    },
                    [],
                  ),
                )
              ]);
            }

            return createEl('td', null, cell)
          })
        )
      }),
    ),
  ]);
}